(function(w){"use strict";const ID="factorial";function parse(v){const s=String(v??"").replace(/,/g,"").trim();if(!/^\d+$/.test(s))return null;const n=Number(s);return Number.isSafeInteger(n)?n:null}function compute(x){const n=parse(x.n);if(n===null)return{error:"0 이상의 정수를 입력해 주세요."};if(n>1000)return{error:"정확한 전체 결과 표시를 위해 1000 이하의 정수를 입력해 주세요."};let r=1n;for(let i=2n;i<=BigInt(n);i++)r*=i;const value=r.toString();return{value,digits:value.length}}function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-field"><label for="hm-factorial-n">n</label><input id="hm-factorial-n" class="hm-calc-input" inputmode="numeric" placeholder="예: 10"><p class="hm-calc-hint">0! = 1이며, n은 0부터 1000까지 지원합니다.</p></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">n! 계산</button><button type="button" class="hm-calc-btn secondary">초기화</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const n=root.querySelector("input"),[go,reset]=root.querySelectorAll("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const r=compute({n:n.value});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("팩토리얼",`<span style="font-size:clamp(15px,2.5vw,24px);word-break:break-all">${r.value}</span>`,`<dl><dt>자릿수</dt><dd>${r.digits}자리</dd></dl>`));});reset.addEventListener("click",()=>{n.value="";api.setMessage(msg,"");api.clearResult(res);n.focus();});}w.HM_CALC.register(ID,{compute,render});})(window);
